import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void threeQueriesBasic() {
        // deltas=[100,-50,200,-30], prefix=[0,100,50,250,220]
        // query [0,1]=50, [1,3]=120, [0,3]=220
        assertArrayEquals(
            new long[]{50L, 120L, 220L},
            new Solution().balanceQueries(
                new int[]{100, -50, 200, -30},
                new int[][]{{0, 1}, {1, 3}, {0, 3}}
            )
        );
    }

    @Test
    void emptyQueries() {
        assertArrayEquals(
            new long[]{},
            new Solution().balanceQueries(
                new int[]{100, -50, 200},
                new int[][]{}
            )
        );
    }

    @Test
    void singleDayQuery() {
        // query {2,2}: only day 2, delta=200
        assertArrayEquals(
            new long[]{200L},
            new Solution().balanceQueries(
                new int[]{100, -50, 200, -30},
                new int[][]{{2, 2}}
            )
        );
    }

    @Test
    void negativeDeltas() {
        // deltas=[-10,-20,-30], prefix=[0,-10,-30,-60]
        // [0,2]=-60, [0,1]=-30, [1,2]=-50
        assertArrayEquals(
            new long[]{-60L, -30L, -50L},
            new Solution().balanceQueries(
                new int[]{-10, -20, -30},
                new int[][]{{0, 2}, {0, 1}, {1, 2}}
            )
        );
    }

    @Test
    void fullRangeQuery() {
        // deltas=[1,2,3,4,5], full range sum=15
        assertArrayEquals(
            new long[]{15L},
            new Solution().balanceQueries(
                new int[]{1, 2, 3, 4, 5},
                new int[][]{{0, 4}}
            )
        );
    }

    @Test
    void longOverflowPrevention() {
        // deltas=[Integer.MAX_VALUE, Integer.MAX_VALUE]
        // sum over [0,1] = 2 * 2147483647 = 4294967294L (overflows int)
        assertArrayEquals(
            new long[]{4294967294L},
            new Solution().balanceQueries(
                new int[]{Integer.MAX_VALUE, Integer.MAX_VALUE},
                new int[][]{{0, 1}}
            )
        );
    }
}
